import{Errors,Functions,Log,ValueConverter}from"Beckhoff.TwinCAT.HMI.Framework/index.esm.js";export function NumberToBigInt(value){const res=ValueConverter.toBigIntEx(value);if(res.error!==Errors.NONE)throw new Error("Converting number to bigint failed with: "+Log.buildMessage(res.details)+".");if(null===res.value)throw new Error("Converting number to bigint failed.");return res.value}Functions.registerFunctionEx("NumberToBigInt","TcHmi.Functions.Beckhoff",NumberToBigInt,{injectInGlobalObject:!0});